SELECT sp.id, sp.question, sp.explanation, sp.subject_id, s.name AS category_name, sp.difficulty, sp.created_at, sp.updated_at FROM subjective_problems sp LEFT JOIN subject s ON s.id = sp.subject_id WHERE 1=1
AND s.name = #{categoryName}
ORDER BY sp.created_at DESC

SELECT sp.id, sp.question, sp.explanation, sp.subject_id, s.name AS category_name, sp.difficulty, sp.created_at, sp.updated_at FROM subjective_problems sp LEFT JOIN subject s ON s.id = sp.subject_id WHERE 1=1
AND s.name = #{category}
ORDER BY sp.created_at DESC
